CREATE TABLE IF NOT EXISTS document_processing_results (
  id SERIAL PRIMARY KEY,
  document_id INTEGER NOT NULL,
  document_type VARCHAR(50),
  ocr_text TEXT,
  extracted_fields JSONB,
  confidence_score DECIMAL(5,2),
  fraud_indicators JSONB,
  validation_status VARCHAR(20) DEFAULT 'pending',
  processed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  processed_by INTEGER
);

CREATE INDEX IF NOT EXISTS idx_doc_processing_document_id ON document_processing_results(document_id);
CREATE INDEX IF NOT EXISTS idx_doc_processing_type ON document_processing_results(document_type);
CREATE INDEX IF NOT EXISTS idx_doc_processing_status ON document_processing_results(validation_status);

